function binarySearch<T>(
  array: T[],
  target: T,
  comparator: (a: T, b: T) => number = (a, b) => {
    if (a < b) return -1;
    if (a > b) return 1;
    return 0;
  }
): number {
  let left = 0;
  let right = array.length - 1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    const comparison = comparator(array[mid], target);

    if (comparison === 0) {
      return mid;
    } else if (comparison < 0) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  return -1; // Not found
}

// Usage examples
const numbers = [1, 3, 5, 7, 9, 11, 13, 15];
console.log(binarySearch(numbers, 7)); // 3

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 3, name: 'Charlie' }
];

console.log(binarySearch(users, { id: 2 }, (a, b) => a.id - b.id)); // 1

class MinPriorityQueue<T> {
  private heap: T[] = [];
  private comparator: (a: T, b: T) => number;

  constructor(comparator: (a: T, b: T) => number) {
    this.comparator = comparator;
  }

  enqueue(value: T): void {
    this.heap.push(value);
    this.siftUp(this.heap.length - 1);
  }

  dequeue(): T | undefined {
    if (this.heap.length === 0) return undefined;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.siftDown(0);
    }

    return min;
  }

  private siftUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.comparator(this.heap[index], this.heap[parentIndex]) < 0) {
        [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
        index = parentIndex;
      } else {
        break;
      }
    }
  }

  private siftDown(index: number): void {
    const length = this.heap.length;
    const leftChild = 2 * index + 1;
    const rightChild = 2 * index + 2;
    let smallest = index;

    if (leftChild < length && this.comparator(this.heap[leftChild], this.heap[smallest]) < 0) {
      smallest = leftChild;
    }
    if (rightChild < length && this.comparator(this.heap[rightChild], this.heap[smallest]) < 0) {
      smallest = rightChild;
    }
    if (smallest !== index) {
      [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
      this.siftDown(smallest);
    }
  }
}

interface Edge {
  to: string;
  weight: number;
}

type Graph = Map<string, Edge[]>;

function dijkstra(graph: Graph, start: string): Map<string, number> {
  const distances = new Map<string, number>();
  const pq = new MinPriorityQueue<{node: string, distance: number}>(
    (a, b) => a.distance - b.distance
  );

  for (const node of graph.keys()) {
    distances.set(node, Infinity);
  }
  distances.set(start, 0);
  pq.enqueue({ node: start, distance: 0 });

  while (pq.heap.length > 0) {
    const { node, distance } = pq.dequeue()!;
    if (distance > distances.get(node)!) continue;

    const edges = graph.get(node) || [];
    for (const edge of edges) {
      const newDistance = distance + edge.weight;
      const currentDistance = distances.get(edge.to) || Infinity;
      if (newDistance < currentDistance) {
        distances.set(edge.to, newDistance);
        pq.enqueue({ node: edge.to, distance: newDistance });
      }
    }
  }

  return distances;
}

interface Interval {
  start: number;
  end: number;
}

function mergeIntervals(intervals: Interval[]): Interval[] {
  if (intervals.length === 0) return [];

  // Sort intervals by start time
  const sorted = [...intervals].sort((a, b) => a.start - b.start);

  const merged: Interval[] = [sorted[0]];

  for (let i = 1; i < sorted.length; i++) {
    const lastMerged = merged[merged.length - 1];
    const current = sorted[i];

    // If intervals overlap, merge them
    if (current.start <= lastMerged.end) {
      lastMerged.end = Math.max(lastMerged.end, current.end);
    } else {
      // No overlap, add new interval
      merged.push(current);
    }
  }

  return merged;
}

// Usage
const intervals: Interval[] = [
  [1, 3], [2, 6], [8, 10], [15, 18]
].map(([start, end]) => ({ start, end }));

console.log(mergeIntervals(intervals));
// Output: [{start: 1, end: 6}, {start: 8, end: 10}, {start: 15, end: 18}]

function topologicalSort(vertices: string[], edges: [string, string][]): string[] {
  // Build adjacency list and in-degree map
  const adjList = new Map<string, string[]>();
  const inDegree = new Map<string, number>();

  // Initialize
  for (const vertex of vertices) {
    adjList.set(vertex, []);
    inDegree.set(vertex, 0);
  }

  // Build graph
  for (const [from, to] of edges) {
    adjList.get(from)!.push(to);
    inDegree.set(to, (inDegree.get(to) || 0) + 1);
  }

  // Queue all vertices with in-degree 0
  const queue: string[] = [];
  for (const [vertex, degree] of inDegree.entries()) {
    if (degree === 0) {
      queue.push(vertex);
    }
  }

  const result: string[] = [];

  while (queue.length > 0) {
    const vertex = queue.shift()!;
    result.push(vertex);

    const neighbors = adjList.get(vertex) || [];
    for (const neighbor of neighbors) {
      const newDegree = (inDegree.get(neighbor) || 0) - 1;
      inDegree.set(neighbor, newDegree);

      if (newDegree === 0) {
        queue.push(neighbor);
      }
    }
  }

  // Check for cycle
  if (result.length !== vertices.length) {
    throw new Error('Graph contains a cycle');
  }

  return result;
}

// Usage
const vertices = ['A', 'B', 'C', 'D', 'E'];
const edges: [string, string][] = [
  ['A', 'C'], ['B', 'C'], ['C', 'D'], ['D', 'E']
];

console.log(topologicalSort(vertices, edges));
// Possible output: ['A', 'B', 'C', 'D', 'E']

class LRUCache<K, V> {
  private capacity: number;
  private cache: Map<K, V>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error('Capacity must be positive');
    }
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: K): V | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }

    // Move accessed item to the end (most recently used)
    const value = this.cache.get(key)!;
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  put(key: K, value: V): void {
    if (this.cache.has(key)) {
      // Update existing key and move to end
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Remove least recently used item (first item in Map)
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }

    this.cache.set(key, value);
  }

  size(): number {
    return this.cache.size;
  }

  clear(): void {
    this.cache.clear();
  }

  keys(): IterableIterator<K> {
    return this.cache.keys();
  }
}

// Usage
const cache = new LRUCache<string, number>(3);
cache.put('a', 1);
cache.put('b', 2);
cache.put('c', 3);
cache.get('a'); // Returns 1, 'a' becomes most recently used
cache.put('d', 4); // Evicts 'b', the least recently used item

class TrieNode<T = string> {
  children: Map<string, TrieNode<T>> = new Map();
  value: T | null = null;
  isEndOfWord: boolean = false;
}

class Trie<T = string> {
  private root: TrieNode<T> = new TrieNode<T>();

  insert(word: string, value: T): void {
    let node = this.root;

    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, new TrieNode<T>());
      }
      node = node.children.get(char)!;
    }

    node.isEndOfWord = true;
    node.value = value;
  }

  search(word: string): T | undefined {
    const node = this.findNode(word);
    return node?.isEndOfWord ? node.value : undefined;
  }

  startsWith(prefix: string): boolean {
    return this.findNode(prefix) !== undefined;
  }

  autocomplete(prefix: string, maxResults: number = 10): Array<{word: string, value: T}> {
    const results: Array<{word: string, value: T}> = [];
    const node = this.findNode(prefix);

    if (!node) return results;

    this.collectWords(node, prefix, results, maxResults);
    return results;
  }

  private findNode(prefix: string): TrieNode<T> | undefined {
    let node = this.root;

    for (const char of prefix) {
      if (!node.children.has(char)) {
        return undefined;
      }
      node = node.children.get(char)!;
    }

    return node;
  }

  private collectWords(
    node: TrieNode<T>,
    prefix: string,
    results: Array<{word: string, value: T}>,
    maxResults: number
  ): void {
    if (results.length >= maxResults) return;

    if (node.isEndOfWord) {
      results.push({ word: prefix, value: node.value! });
    }

    for (const [char, child] of node.children) {
      this.collectWords(child, prefix + char, results, maxResults);
    }
  }

  delete(word: string): boolean {
    return this.deleteHelper(this.root, word, 0);
  }

  private deleteHelper(node: TrieNode<T>, word: string, depth: number): boolean {
    if (depth === word.length) {
      if (!node.isEndOfWord) return false;
      node.isEndOfWord = false;
      node.value = null;
      return node.children.size === 0;
    }

    const char = word[depth];
    const child = node.children.get(char);

    if (!child) return false;

    const shouldDeleteChild = this.deleteHelper(child, word, depth + 1);

    if (shouldDeleteChild) {
      node.children.delete(char);
      return !node.isEndOfWord && node.children.size === 0;
    }

    return false;
  }
}

export { Trie, TrieNode };

function memoize<T extends (...args: any[]) => any>(fn: T): T {
  const cache = new Map<string, ReturnType<T>>();

  return ((...args: any[]) => {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      return cache.get(key)!;
    }

    const result = fn(...args);
    cache.set(key, result);

    return result;
  }) as T;
}

// Basic memoized Fibonacci
const fibonacci = memoize((n: number): number => {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
});

// Memoized with custom key function
function memoizedFibonacciCustom(n: number): number {
  const cache = new Map<number, number>();

  const fib = (num: number): number => {
    if (num in cache) return cache.get(num)!;
    if (num <= 1) return num;

    const result = fib(num - 1) + fib(num - 2);
    cache.set(num, result);
    return result;
  };

  return fib(n);
}

// Bottom-up approach
function fibonacciBottomUp(n: number): number {
  if (n <= 1) return n;

  const dp = new Array(n + 1).fill(0);
  dp[1] = 1;

  for (let i = 2; i <= n; i++) {
    dp[i] = dp[i - 1] + dp[i - 2];
  }

  return dp[n];
}

// Space-optimized bottom-up
function fibonacciOptimized(n: number): number {
  if (n <= 1) return n;

  let prev2 = 0;
  let prev1 = 1;

  for (let i = 2; i <= n; i++) {
    const current = prev1 + prev2;
    prev2 = prev1;
    prev1 = current;
  }

  return prev1;
}

console.log(fibonacci(50)); // 12586269025
console.log(fibonacciBottomUp(50)); // 12586269025
console.log(fibonacciOptimized(50)); // 12586269025

function quickSelect<T>(
  array: T[],
  k: number,
  comparator: (a: T, b: T) => number = (a, b) => {
    if (a < b) return -1;
    if (a > b) return 1;
    return 0;
  }
): T {
  if (array.length === 0) {
    throw new Error('Array is empty');
  }

  if (k < 1 || k > array.length) {
    throw new Error('k is out of bounds');
  }

  return quickSelectHelper(array, 0, array.length - 1, k - 1, comparator);
}

function quickSelectHelper<T>(
  array: T[],
  left: number,
  right: number,
  k: number,
  comparator: (a: T, b: T) => number
): T {
  if (left === right) {
    return array[left];
  }

  // Choose pivot randomly
  const pivotIndex = left + Math.floor(Math.random() * (right - left + 1));
  const pivotNewIndex = partition(array, left, right, pivotIndex, comparator);

  if (k === pivotNewIndex) {
    return array[k];
  } else if (k < pivotNewIndex) {
    return quickSelectHelper(array, left, pivotNewIndex - 1, k, comparator);
  } else {
    return quickSelectHelper(array, pivotNewIndex + 1, right, k, comparator);
  }
}

function partition<T>(
  array: T[],
  left: number,
  right: number,
  pivotIndex: number,
  comparator: (a: T, b: T) => number
): number {
  const pivotValue = array[pivotIndex];

  // Move pivot to end
  swap(array, pivotIndex, right);

  let storeIndex = left;

  for (let i = left; i < right; i++) {
    if (comparator(array[i], pivotValue) < 0) {
      swap(array, storeIndex, i);
      storeIndex++;
    }
  }

  // Move pivot to its final place
  swap(array, storeIndex, right);

  return storeIndex;
}

function swap<T>(array: T[], i: number, j: number): void {
  [array[i], array[j]] = [array[j], array[i]];
}

// Usage
const numbers = [3, 2, 1, 5, 6, 4];
console.log(quickSelect(numbers, 2)); // 2nd smallest: 2
console.log(quickSelect(numbers, 4)); // 4th smallest: 4
